INSERT INTO words (word, category_id, position, tag, zh, en, example_en, example_zh, synonyms) VALUES
  ('let', 'op', 6, 'OP', '让；允许；放任', 'allow someone or something to do or be done', 'Let the young girl put the book on the shelf.', '让这个小女孩把书放到架子上。', '[{"w":"keep","def":"keep: 相关的动作或关系词","vs":"与 let 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"keep\" / \"let\" 的替换练习"},{"w":"make","def":"make: 可帮助扩展句型的基础词","vs":"与 let 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"make\" / \"let\" 的替换练习"},{"w":"put","def":"put: 同一组 Basic English 操作词","vs":"与 let 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"put\" / \"let\" 的替换练习"}]'),
  ('make', 'op', 7, 'OP', '做；制造；使成为', 'create something or cause a condition to happen', 'They make bread in this warm kitchen.', '他们在这个温暖的厨房里做面包。', '[{"w":"let","def":"let: 相关的动作或关系词","vs":"与 make 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"let\" / \"make\" 的替换练习"},{"w":"put","def":"put: 可帮助扩展句型的基础词","vs":"与 make 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"put\" / \"make\" 的替换练习"},{"w":"seem","def":"seem: 同一组 Basic English 操作词","vs":"与 make 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"seem\" / \"make\" 的替换练习"}]'),
  ('put', 'op', 8, 'OP', '放；置于某处', 'place something in a position', 'Put the key under the small stone.', '把钥匙放在小石头下面。', '[{"w":"make","def":"make: 相关的动作或关系词","vs":"与 put 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"make\" / \"put\" 的替换练习"},{"w":"seem","def":"seem: 可帮助扩展句型的基础词","vs":"与 put 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"seem\" / \"put\" 的替换练习"},{"w":"take","def":"take: 同一组 Basic English 操作词","vs":"与 put 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"take\" / \"put\" 的替换练习"}]'),
  ('seem', 'op', 9, 'OP', '似乎；看起来像', 'appear to be true or to have a certain quality', 'The answer may seem simple, but it is important.', '这个答案可能看起来简单，但它很重要。', '[{"w":"put","def":"put: 相关的动作或关系词","vs":"与 seem 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"put\" / \"seem\" 的替换练习"},{"w":"take","def":"take: 可帮助扩展句型的基础词","vs":"与 seem 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"take\" / \"seem\" 的替换练习"},{"w":"be","def":"be: 同一组 Basic English 操作词","vs":"与 seem 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"be\" / \"seem\" 的替换练习"}]'),
  ('take', 'op', 10, 'OP', '拿；带走；接受；花费', 'get hold of something, carry it, accept it, or use time', 'Take this coat with you because the night is cold.', '带上这件外衣，因为夜里很冷。', '[{"w":"seem","def":"seem: 相关的动作或关系词","vs":"与 take 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"seem\" / \"take\" 的替换练习"},{"w":"be","def":"be: 可帮助扩展句型的基础词","vs":"与 take 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"be\" / \"take\" 的替换练习"},{"w":"do","def":"do: 同一组 Basic English 操作词","vs":"与 take 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"do\" / \"take\" 的替换练习"}]');
